using sv_98a5dd2b8c7b4ff987797a1283f120e9.Models;

namespace sv_98a5dd2b8c7b4ff987797a1283f120e9.Services;

public class ApplicationService : IApplicationService
{
    private static int _nextId = 1000;

    public async Task<int> SubmitApplicationAsync(JobApplication application)
    {
        await Task.Delay(1000);
        return Interlocked.Increment(ref _nextId);
    }

    public async Task<bool> ValidateEmailAsync(string email)
    {
        await Task.Delay(300);
        return !string.IsNullOrWhiteSpace(email)
               && email.Contains('@')
               && email.Contains('.');
    }
}

@namespace sv_98a5dd2b8c7b4ff987797a1283f120e9.Components.Pages.Application

<nav aria-label="Application steps" class="mb-4">
    <ol class="d-flex list-unstyled justify-content-between step-indicator">
        @for (int i = 0; i < StepNames.Length; i++)
        {
            var step = i;
            var isCurrent = step == CurrentStep;
            var isCompleted = CompletedSteps.Contains(step);
            var isFuture = !isCurrent && !isCompleted;

            <li class="text-center flex-fill @(isCurrent ? "step-current" : "") @(isCompleted ? "step-completed" : "") @(isFuture ? "step-future" : "")">
                @if (isCompleted)
                {
                    <button class="btn btn-link text-decoration-none p-0" @onclick="() => OnStepClicked.InvokeAsync(step)">
                        <span class="badge rounded-circle bg-success me-1">✓</span>
                        <span class="text-success fw-semibold">@StepNames[step]</span>
                    </button>
                }
                else if (isCurrent)
                {
                    <span class="badge rounded-circle bg-primary me-1">@(step + 1)</span>
                    <span class="fw-semibold text-primary">@StepNames[step]</span>
                }
                else
                {
                    <span class="badge rounded-circle bg-secondary me-1">@(step + 1)</span>
                    <span class="text-muted">@StepNames[step]</span>
                }
            </li>
        }
    </ol>
</nav>

@code {
    private static readonly string[] StepNames =
        ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];

    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public HashSet<int> CompletedSteps { get; set; } = [];
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }
}

@namespace sv_98a5dd2b8c7b4ff987797a1283f120e9.Components.Pages.Application
@using sv_98a5dd2b8c7b4ff987797a1283f120e9.Models

<div class="card mb-3">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-center mb-3">
            <h6 class="card-title mb-0">Reference @Index</h6>
            @if (CanRemove)
            {
                <button class="btn btn-outline-danger btn-sm" @onclick="() => OnRemove.InvokeAsync()">Remove</button>
            }
        </div>

        <div class="row g-3">
            <div class="col-md-6">
                <label class="form-label">Name</label>
                <input class="form-control" @bind="Reference.Name" @bind:event="oninput" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Relationship</label>
                <input class="form-control" @bind="Reference.Relationship" @bind:event="oninput" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Email</label>
                <input type="email" class="form-control" @bind="Reference.Email" @bind:event="oninput" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Phone</label>
                <input type="tel" class="form-control" @bind="Reference.Phone" @bind:event="oninput" />
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public ReferenceModel Reference { get; set; } = default!;
    [Parameter] public int Index { get; set; }
    [Parameter] public bool CanRemove { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }
}

@namespace sv_98a5dd2b8c7b4ff987797a1283f120e9.Components.Pages.Application
@using sv_98a5dd2b8c7b4ff987797a1283f120e9.Models

<h4 class="mb-3">Personal Information</h4>

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

<div class="row g-3">
    <div class="col-md-6">
        <label class="form-label">Full Name <span class="text-danger">*</span></label>
        <input class="form-control" @bind="Model.FullName" @bind:event="oninput" />
