@page "/apply"
@namespace sv_98a5dd2b8c7b4ff987797a1283f120e9.Components.Pages.Application
@rendermode InteractiveServer
@using sv_98a5dd2b8c7b4ff987797a1283f120e9.Models
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    <StepIndicator CurrentStep="currentStep"
                   CompletedSteps="completedSteps"
                   OnStepClicked="GoToStep" />

    <div class="mt-4">
        @switch (currentStep)
        {
            case 0:
                <PersonalInfoStep Model="personalInfo"
                                  ApplicationService="ApplicationService"
                                  OnNext="NextStep" />
                break;
            case 1:
                <WorkHistoryStep Entries="workEntries"
                                 OnNext="NextStep"
                                 OnBack="PreviousStep" />
                break;
            case 2:
                <ReferencesStep References="references"
                                OnNext="NextStep"
                                OnBack="PreviousStep" />
                break;
            case 3:
                <CoverLetterStep CoverLetter="@coverLetter"
                                 CoverLetterChanged="val => coverLetter = val"
                                 OnNext="NextStep"
                                 OnBack="PreviousStep" />
                break;
            case 4:
                <ReviewStep Personal="personalInfo"
                            WorkEntries="workEntries"
                            References="references"
                            CoverLetter="@coverLetter"
                            SubmittedId="submittedId"
                            OnEdit="GoToStep"
                            OnBack="PreviousStep"
                            OnSubmit="SubmitApplication" />
                break;
        }
    </div>
</div>

@code {
    private int currentStep;
    private readonly HashSet<int> completedSteps = [];

    private readonly PersonalInfoModel personalInfo = new();
    private readonly List<WorkEntryModel> workEntries = [new()];
    private readonly List<ReferenceModel> references = [new(), new()];
    private string coverLetter = "";
    private int? submittedId;

    private void NextStep()
    {
        completedSteps.Add(currentStep);
        if (currentStep < 4)
            currentStep++;
    }

    private void PreviousStep()
    {
        if (currentStep > 0)
            currentStep--;
    }

    private void GoToStep(int step)
    {
        if (completedSteps.Contains(step) || step == currentStep)
            currentStep = step;
    }

    private async Task SubmitApplication(JobApplication application)
    {
        submittedId = await ApplicationService.SubmitApplicationAsync(application);
    }
}

using sv_98a5dd2b8c7b4ff987797a1283f120e9.Models;

namespace sv_98a5dd2b8c7b4ff987797a1283f120e9.Services;

public class ApplicationService : IApplicationService
{
    private static int _nextId = 1000;

    public async Task<int> SubmitApplicationAsync(JobApplication application)
    {
        await Task.Delay(1000);
        return Interlocked.Increment(ref _nextId);
    }

    public async Task<bool> ValidateEmailAsync(string email)
    {
        await Task.Delay(300);
        return !string.IsNullOrWhiteSpace(email)
               && email.Contains('@')
               && email.Contains('.');
    }
}

@namespace sv_98a5dd2b8c7b4ff987797a1283f120e9.Components.Pages.Application

<nav aria-label="Application steps" class="mb-4">
    <ol class="d-flex list-unstyled justify-content-between step-indicator">
        @for (int i = 0; i < StepNames.Length; i++)
        {
            var step = i;
            var isCurrent = step == CurrentStep;
            var isCompleted = CompletedSteps.Contains(step);
            var isFuture = !isCurrent && !isCompleted;

            <li class="text-center flex-fill @(isCurrent ? "step-current" : "") @(isCompleted ? "step-completed" : "") @(isFuture ? "step-future" : "")">
                @if (isCompleted)
                {
                    <button class="btn btn-link text-decoration-none p-0" @onclick="() => OnStepClicked.InvokeAsync(step)">
                        <span class="badge rounded-circle bg-success me-1">✓</span>
                        <span class="text-success fw-semibold">@StepNames[step]</span>
                    </button>
                }
                else if (isCurrent)
                {
                    <span class="badge rounded-circle bg-primary me-1">@(step + 1)</span>
                    <span class="fw-semibold text-primary">@StepNames[step]</span>
                }
                else
                {
                    <span class="badge rounded-circle bg-secondary me-1">@(step + 1)</span>
                    <span class="text-muted">@StepNames[step]</span>
                }
            </li>
        }
    </ol>
</nav>

