@namespace sv_98a5dd2b8c7b4ff987797a1283f120e9.Components.Pages.Application

<nav aria-label="Application steps" class="mb-4">
    <ol class="d-flex list-unstyled justify-content-between step-indicator">
        @for (int i = 0; i < StepNames.Length; i++)
        {
            var step = i;
            var isCurrent = step == CurrentStep;
            var isCompleted = CompletedSteps.Contains(step);
            var isFuture = !isCurrent && !isCompleted;

            <li class="text-center flex-fill @(isCurrent ? "step-current" : "") @(isCompleted ? "step-completed" : "") @(isFuture ? "step-future" : "")">
                @if (isCompleted)
                {
                    <button class="btn btn-link text-decoration-none p-0" @onclick="() => OnStepClicked.InvokeAsync(step)">
                        <span class="badge rounded-circle bg-success me-1">✓</span>
                        <span class="text-success fw-semibold">@StepNames[step]</span>
                    </button>
                }
                else if (isCurrent)
                {
                    <span class="badge rounded-circle bg-primary me-1">@(step + 1)</span>
                    <span class="fw-semibold text-primary">@StepNames[step]</span>
                }
                else
                {
                    <span class="badge rounded-circle bg-secondary me-1">@(step + 1)</span>
                    <span class="text-muted">@StepNames[step]</span>
                }
            </li>
        }
    </ol>
</nav>

