@namespace sv_98a5dd2b8c7b4ff987797a1283f120e9.Components.Pages.Application

<h4 class="mb-3">Cover Letter</h4>

<div class="mb-3">
    <label class="form-label">Write your cover letter</label>
    <textarea class="form-control" rows="12"
              @bind="CoverLetter"
              @bind:event="oninput"
              @bind:after="OnTextChanged"
              maxlength="@MaxLength"></textarea>
    <div class="form-text text-end">
        @CoverLetter.Length / @MaxLength characters
    </div>
</div>

<div class="d-flex justify-content-between mt-3">
    <button class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="() => OnNext.InvokeAsync()">Next</button>
</div>

@code {
    private const int MaxLength = 2000;

    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<string> CoverLetterChanged { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private async Task OnTextChanged()
    {
        await CoverLetterChanged.InvokeAsync(CoverLetter);
    }
}

@namespace sv_98a5dd2b8c7b4ff987797a1283f120e9.Components.Pages.Application
@using sv_98a5dd2b8c7b4ff987797a1283f120e9.Models

<h4 class="mb-3">Review & Submit</h4>

@if (SubmittedId is not null)
{
    <div class="alert alert-success">
        <h5>Application Submitted!</h5>
        <p>Your application has been received. Your application ID is <strong>#@SubmittedId</strong>.</p>
    </div>
}
else
{
    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="alert alert-danger">@ErrorMessage</div>
    }

    <!-- Personal Info -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Personal Information</strong>
            <button class="btn btn-sm btn-link" @onclick="() => OnEdit.InvokeAsync(0)">Edit</button>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6"><strong>Name:</strong> @Personal.FullName</div>
                <div class="col-md-6"><strong>Email:</strong> @Personal.Email</div>
                <div class="col-md-6"><strong>Phone:</strong> @Personal.Phone</div>
                <div class="col-md-6"><strong>Address:</strong> @Personal.Address</div>
            </div>
        </div>
    </div>

    <!-- Work History -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Work History</strong>
            <button class="btn btn-sm btn-link" @onclick="() => OnEdit.InvokeAsync(1)">Edit</button>
        </div>
        <div class="card-body">
            @foreach (var entry in WorkEntries)
            {
                <div class="mb-3 pb-3 border-bottom">
                    <div><strong>@entry.Title</strong> at @entry.Company</div>
                    <div class="text-muted">
                        @entry.StartDate.ToString("MMM yyyy") —
                        @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                    </div>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <div class="mt-1">@entry.Description</div>
                    }
                </div>
            }
        </div>
    </div>

    <!-- References -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>References</strong>
            <button class="btn btn-sm btn-link" @onclick="() => OnEdit.InvokeAsync(2)">Edit</button>
        </div>
        <div class="card-body">
            @foreach (var r in References)
            {
                <div class="mb-2">
                    <strong>@r.Name</strong> (@r.Relationship) — @r.Email, @r.Phone
                </div>
            }
        </div>
    </div>

    <!-- Cover Letter -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Cover Letter</strong>
            <button class="btn btn-sm btn-link" @onclick="() => OnEdit.InvokeAsync(3)">Edit</button>
        </div>
        <div class="card-body">
            <p style="white-space: pre-wrap;">@CoverLetter</p>
        </div>
    </div>

    <div class="d-flex justify-content-between mt-4">
        <button class="btn btn-secondary" @onclick="OnBack">Back</button>
        <button class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@isSubmitting">
            @if (isSubmitting)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Submit Application
        </button>
    </div>
}

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Personal { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntryModel> WorkEntries { get; set; } = [];
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = [];
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<int> OnEdit { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback<JobApplication> OnSubmit { get; set; }
    [Parameter] public int? SubmittedId { get; set; }

    private bool isSubmitting;
    private string? ErrorMessage;

    private async Task HandleSubmit()
    {
        isSubmitting = true;
        ErrorMessage = null;
        try
        {
            var application = new JobApplication(
                Personal.ToRecord(),
                new WorkHistory(WorkEntries.Select(e => e.ToRecord()).ToList()),
                References.Select(r => r.ToRecord()).ToList(),
                CoverLetter
            );
            await OnSubmit.InvokeAsync(application);
        }
        catch (Exception ex)
        {
            ErrorMessage = $"Submission failed: {ex.Message}";
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

@page "/apply"
@namespace sv_98a5dd2b8c7b4ff987797a1283f120e9.Components.Pages.Application
@rendermode InteractiveServer
@using sv_98a5dd2b8c7b4ff987797a1283f120e9.Models
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    <StepIndicator CurrentStep="currentStep"
                   CompletedSteps="completedSteps"
                   OnStepClicked="GoToStep" />

    <div class="mt-4">
        @switch (currentStep)
        {
            case 0:
                <PersonalInfoStep Model="personalInfo"
                                  ApplicationService="ApplicationService"
                                  OnNext="NextStep" />
                break;
            case 1:
                <WorkHistoryStep Entries="workEntries"
                                 OnNext="NextStep"
                                 OnBack="PreviousStep" />
                break;
            case 2:
                <ReferencesStep References="references"
                                OnNext="NextStep"
                                OnBack="PreviousStep" />
                break;
            case 3:
                <CoverLetterStep CoverLetter="@coverLetter"
                                 CoverLetterChanged="val => coverLetter = val"
                                 OnNext="NextStep"
                                 OnBack="PreviousStep" />
                break;
            case 4:
                <ReviewStep Personal="personalInfo"
                            WorkEntries="workEntries"
                            References="references"
                            CoverLetter="@coverLetter"
                            SubmittedId="submittedId"
                            OnEdit="GoToStep"
                            OnBack="PreviousStep"
                            OnSubmit="SubmitApplication" />
                break;
        }
    </div>
</div>

@code {
    private int currentStep;
    private readonly HashSet<int> completedSteps = [];

    private readonly PersonalInfoModel personalInfo = new();
    private readonly List<WorkEntryModel> workEntries = [new()];
    private readonly List<ReferenceModel> references = [new(), new()];
    private string coverLetter = "";
    private int? submittedId;

    private void NextStep()
    {
        completedSteps.Add(currentStep);
        if (currentStep < 4)
            currentStep++;
    }

    private void PreviousStep()
    {
        if (currentStep > 0)
            currentStep--;
    }

    private void GoToStep(int step)
    {
        if (completedSteps.Contains(step) || step == currentStep)
            currentStep = step;
    }

    private async Task SubmitApplication(JobApplication application)
    {
        submittedId = await ApplicationService.SubmitApplicationAsync(application);
    }
}

